css:
/* 朝雾 v1.0 2025-12-22
   作者：咩野(DC@lambkinling)
   请勿二传二改，倒卖&商用引流司马 */

/* 看不清字就把酒馆自带的主要文本颜色改深一些，文本阴影宽度拉到0，不要勾选禁用文本阴影😱 */

@import url("https://fontsapi.zeoseven.com/5/main/result.css");

body {
    font-family: "ChillKai";
    font-weight: normal;
}

:root {
  --混合: color-mix(in srgb, var(--SmartThemeBorderColor) 40%, #fff);
  --下划线: color-mix(in srgb, var(--SmartThemeUnderlineColor) 20%, #fff);
}

/* ===== 文本样式 ===== */
/* 对话 */
q {
  position: relative;
  background-image: 
    linear-gradient(to top,
    white 0%, transparent 5px, transparent calc(100% - 5px), white 100%),
    linear-gradient(to right,
    transparent 0%, var(--下划线) 20px, var(--下划线) calc(100% - 20px), transparent 100%);
  border-radius: 1px;
  box-shadow: 1px 1px 1px rgba(0, 0, 0, 0.08);
}

/* 斜体 */
em {
  color: #fff !important; 
  text-shadow: 
    0 0 1px var(--SmartThemeEmColor), 
    0 0 2.5px var(--SmartThemeEmColor);
}

/* 删除 */
del {
  color: var(--SmartThemeUnderlineColor);
  text-decoration-color: crimson;
}

/* 代码块 */
code {
  color: #ffffff !important;
  background: var(--SmartThemeBorderColor) !important;
  border: none;
  box-shadow: 1px 1px 1px var(--SmartThemeBorderColor) !important;
}

.mes pre code {
  position: relative;
  border-radius: 3px;
  border: none;
  box-shadow:
    inset 0 0 13px rgba(178, 178, 178, 0.15),
    1px 1px 2px rgba(55, 55, 55, 0.2) !important;
  background-color: #fff  !important;
  background-image: url("https://files.catbox.moe/7bgdl4.png")  !important;
  background-size: 100% auto;
  background-repeat: repeat;
}

/* md引用文本 */
blockquote {
  background: linear-gradient(to right, #fff, var(--下划线), transparent) !important;
  border-color: var(--SmartThemeEmColor) !important;
}


/* 代码块内文字 */
.hljs {
  color: var(--SmartThemeBodyColor) !important;
  font-size: var(--mainFontSize) !important;
  line-height: 1.6;
}


hr {
  background: color-mix(in srgb, var(--SmartThemeBorderColor) 75%, transparent);
}

/* 选中文字高亮 */
::selection {
  background: color-mix(in srgb, var(--SmartThemeQuoteColor) 50%, white);
  color: var(--SmartThemeBodyColor);
}

/* 全局头像 */
.avatar img,
body.big-avatar .avatar img{
  box-shadow: none;
  border: none;
}
.avatar:not(.mes .avatar):not(
#HotSwapWrapper .avatar) {
  position: relative;
  &::before {
    content: "";
    position: absolute;
    aspect-ratio: 1 / 1;
    width: 140%;
    top: 47%;
    left: 50%;
    transform: translate(-50%, -50%);
    background: url("https://files.catbox.moe/6yta6e.png");
    background-size: 100%
  }
}

/* ===== 滚动条 ===== */
::-webkit-scrollbar {
  width: 4px;
}

::-webkit-scrollbar-thumb {
  background:
    linear-gradient(135deg, var(--SmartThemeBorderColor) 0%, var(--SmartThemeBlurTintColor) 100%);
  border: 0.2px solid var(--SmartThemeBorderColor) !important;
  box-shadow: none !important;
}

#chat::-webkit-scrollbar {
    display: none;
}

/* ----- 滑动条 ----- */
input[type="range"] {
  background: 
    linear-gradient(185deg, var(--SmartThemeBorderColor) 0%, var(--SmartThemeBlurTintColor) 100%) !important;
  border-radius: 15px !important;
  height: 5px !important;
  filter: none !important;
  box-shadow: 
    1px 1px 1px var(--混合),
    -1px -1px 1px rgba(197, 197, 197, 0.1) !important;
}

input[type="range"]::-webkit-slider-thumb {
  filter: none !important;
  background: 
    linear-gradient(135deg, var(--SmartThemeBorderColor) 0%, var(--SmartThemeBlurTintColor) 100%);
  border-radius: 50%;
  border: none;
  box-shadow: 
    1px 1px 1px rgba(0, 0, 0, 0.2),
    -1px -1px 1px rgba(197, 197, 197, 0.1);
}

/* ===== 顶栏 ===== */
#top-bar,
body.no-blur #top-bar {
  box-shadow: none !important;
  outline: 1px solid var(--SmartThemeBlurTintColor) !important;
}

.drawer-icon.fa-fw {
  display: flex;
  overflow: visible;
  justify-content: center;
  font-size: calc(var(--mainFontSize) * 1.15);
}

/* 顶栏图标 */
#leftNavDrawerIcon::before { 
  content: "\f0ae";
}

/* 插头 */
#API-status-top:not(.redOverlayGlow)::before {
  content: "\f0c6";
}

/* 未连接状态 */
#API-status-top.redOverlayGlow::before {
  content: "\f714" !important;
}

#advanced-formatting-button .drawer-icon::before {
  content: "\f1dc";
}

#WI-SP-button .drawer-icon::before {
  content: "\f02a";
}

#user-settings-button .drawer-icon::before {
    content: "\f49e";
}

#backgrounds-drawer-toggle .drawer-icon::before {
  content: "\f302";
}

#extensions-settings-button .drawer-icon::before {
  content: "\f1ea";
}

#persona-management-button .drawer-icon::before {
  content: "\f21e";
}

#rightNavDrawerIcon::before {
  content: "\f2b9";
}

/* 顶栏(补记忆表格) */
#table_drawer_icon.drawer-icon::before {
    content: "\f080";
}

.drawer-icon.fa-fw:hover {
  filter: drop-shadow(0 0 3px rgba(128, 128, 128, 0.35));
  transform: scale(1.05);
  transition: filter 0.3s ease, transform 0.3s ease;
}

/* top-bar插件 */
#extensionTopBar {
  border: none !important;
  border-bottom: 1px solid var(--混合) !important;
  border-radius: 0 0 5px 5px !important;
}

/* ===== 输入框 ===== */
/* 底栏宽度 */
#send_form {
  width: 92%;
}

#send_form, 
body.no-blur #send_form {
  border-radius: 8px;
  padding: 3px;
  border: 1.2px solid var(--SmartThemeBorderColor) !important;
  outline: 2px solid var(--SmartThemeBlurTintColor) !important;
  box-shadow:
    inset 0 0 20px rgba(255, 255, 255, 0.8),
    0 0 10px rgba(255, 255, 255, 1),
    0 0 7px rgba(255, 255, 255, 0.85);
}

#send_textarea {
  clip-path: none !important;
  box-shadow: none !important;
  border: none;
}

#send_form textarea:focus {
  box-shadow: 
    1px 1px 2.5px var(--混合),
    inset 0 0 15px var(--SmartThemeBlurTintColor);
  background-color: color-mix(in srgb, var(--SmartThemeBorderColor) 15%, #fff);
}

/* 底栏图标 */
#quick-reply-rocket-button,
#send_form .fa-solid {
  font-size: calc(var(--mainFontSize) * 1.25);
  color: var(--SmartThemeBorderColor);
}

#options_button::before {
    content: "\f10d";
}

#extensionsMenuButton::before {
    content: "\f891";
}

#send_but::before {
    content: "\f10e";
}

#mes_stop i::before {
    content: "\f05e";
    color: crimson;
}

/* 输入框文案自定义 */
#send_textarea::placeholder {
    opacity: 0;
}

#nonQRFormItems {
    position: relative;
    display: flex;
    align-items: center;
}

/* 📍输入框文案 */
#nonQRFormItems::before {
    content: "₊⁺₊⊹𝑴𝒊𝒔𝒕𝒊𝒔𝒍𝒆'𝒔𝑬𝒄𝒉𝒐 𓏸˚𓈒⁺₊⁺";
    position: absolute;
    left: calc(50% + 20px); /* 左右位置 */
    top: 50%;
    transform: translate(-50%, -50%);
    font-size: calc(var(--mainFontSize) * 0.9);
    color: var(--SmartThemeBorderColor);
    pointer-events: none;
    z-index: 1;
}

#nonQRFormItems:has(#send_textarea:focus)::before,
#nonQRFormItems:has(#send_textarea:not(:placeholder-shown))::before {
    display: none !important;
}

/* 底栏悬浮 by NAKARI */
#form_sheld {
  position: absolute;
  bottom: 5px;  /* 底栏与输入框距离 */
}

#chat {
  max-height: calc(100dvh + var(--bottomFormBlockSize));
  height: calc(100dvh + var(--bottomFormBlockSize));
}

/* 消除导航栏+底栏的缝隙，同时让底栏紧贴界面底部 by zzzskari */
#form_sheld {
  margin: 0 auto !important;
}

#sheld {
  top: var(--bottomFormBlockSize);
  height: calc(100dvh - var(--bottomFormBlockSize));
  max-height: calc(100dvh - var(--bottomFormBlockSize));
}

/* 当 textarea 聚焦或有内容时 */
#form_sheld:has(#send_textarea:focus),
#form_sheld:has(#send_textarea:not(:placeholder-shown)) {
  position: sticky;
}

.list-group,
.options-content,
#options {
  box-shadow: none !important;
}

/* quickPersona */
#quickPersonaImg {
    box-shadow: none !important;
}

.list-group-item .quickPersonaMenuImg {
    box-shadow: none;
    border: none;
}

#qr--bar > .qr--buttons .qr--button {
  border: none !important;
  border-radius: 2px !important;
  background: transparent;
  box-shadow:
    1px 1px 2px var(--SmartThemeBorderColor),
    0 0 2px var(--SmartThemeBorderColor) !important;
}

/* ===== 消息区域 ===== */
#chat {
  border: none;
}

/* --- 欢迎页 --- */
.welcomePanel {
  background: none !important;
  border: none !important;
}

.welcomePanel .recentChatList .recentChat {
    margin-bottom: 10px;
    border-radius: 5px;
    background-color: var(--SmartThemeBlurTintColor);
    outline: 1.5px solid var(--SmartThemeBlurTintColor) !important;
    box-shadow:
      0 0 3px rgba(255, 255, 255, 0.85),
      0 0 7px rgba(255, 255, 255, 0.85);
}

.chatNameContainer {
    padding: 1px 3.5px;
}

.mes_button.showRecentChats .fa-circle-chevron-down::before {
  content: "\f0e0";
}

.mes_button.hideRecentChats .fa-circle-xmark::before {
  content: "\f658";
}

.mes_button.hideRecentChats,
.mes_button.showRecentChats {
  opacity: 0.55;
  visibility: visible;
}

/* --- 思维链 --- */
.mes_reasoning_header {
  background-color: transparent;
  margin: 0 auto;
}

.mes_reasoning_arrow {
  display: none;
}

/* 📍思维链文字自定义 */
.mes_reasoning_header_title {
  font-size: 0;
  &::before {
    content: "• 𝒂𝒏𝒐𝒏𝒚𝒎𝒐𝒖𝒔 𝒍𝒆𝒕𝒕𝒆𝒓 •";
    font-size: calc(var(--mainFontSize) * 0.9);
    color: var(--SmartThemeEmColor);
    border-radius: 5px;
    padding: 2px 6px;
    box-shadow:
      0 0 2.5px var(--混合),
      1px 1px 2.5px var(--混合),
      inset 0 0 12px #fff;
  }
}

@media (max-width: 768px) {
  .mes_reasoning_details {
    position: relative;
}

  .mes_reasoning_details[open] {
  width: 100%;
}

  .mes_reasoning {
    width: 100%;
    max-height: 500px; /* 内容高度 */
    overflow: hidden auto;
    font-size: calc(var(--mainFontSize) * 0.9);
    border-radius: 8px;
    border: 1px dotted var(--SmartThemeBorderColor);
    background: color-mix(in srgb, var(--SmartThemeUnderlineColor) 15%, #fff);
  }

  .mes_reasoning_actions {
     position: absolute;
     right: 5px;
     top: 5px;
     z-index: 10;
     flex-shrink: 0;
     padding: 0 5px;
  }
}

/* --- 最新消息 --- */
.last_mes {
  margin-bottom: 60px !important;
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 0px;
}

.last_mes[is_user="false"] .mes_block {
  margin-bottom: 30px !important;
}

/* --- 消息框 ---*/
.mes {
  flex-direction: column;
  position: relative;
  width: calc(100% - 15px);
  margin: 15px auto;
  padding: 12px 7px 17px;
  border-radius: 5px;
  box-shadow: 0 0 1px rgba(55, 55, 55, 0.1);
  background-color: rgba(255, 255, 255);
  box-shadow:
    0 0 2px rgba(255, 255, 255, 0.85),
    0 0 5px rgba(255, 255, 255, 0.85),
    inset 0 0 45px rgba(255, 255, 255, 0.95);
}

/* --- 文本区域 --- */
.mes_block {
  display: flex;
  flex-direction: column;
  overflow: visible;
  transform: none !important;
  padding: 5px 0 0;
  border-top: 1px dashed var(--SmartThemeBorderColor);
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  background: url("https://files.catbox.moe/xswf7x.png");
  background-size: 100% auto;
  background-repeat: repeat-y;
}

/* --- 文本框 --- */
.mes_text {
  padding: 0 2px;
  text-align: justify;
}

.mes[is_user="true"] .mes_text {
  padding: 5px 0;
}

.mes[is_user="true"] p:last-child {
  margin-bottom: 0;
}

.mes_text p:empty {
    display: none;
}

/* 首行缩进 */
.mes_text p {
  text-indent: 2em;
}

/* --- 小铅笔 --- */
.mes_button,
.mes_edit_buttons {
  font-size: calc(var(--mainFontSize) * 1.01);
  filter: none !important;
  color: var(--SmartThemeBorderColor);
}

.mes .menu_button {
  opacity: 1;
  color: #888;
  transform: scale(0.85);
  border-radius: 8px;
  border: none;
  box-shadow:
    0 0 5px rgba(55, 55, 55, 0.15),
    1px 1px 3px var(--混合),
    inset 0 0 20px var(--SmartThemeBlurTintColor);
}

.mes .fa-star::before {
  content: "\f02b" !important; 
}

#chat .fa-solid.fa-star {
   color: #FF787D !important;
}

.fa-star::before {
    content: "\f004" !important; 
}

.fa-solid.fa-star {
   color: red !important;
}

.mes_edit::before {
    content: "\f00c";
}

.extraMesButtonsHint::before {
    content: "\f00d" !important;
}

/* --- 左右箭头 --- */
.swipe_right,
.swipe_left {
  opacity: 0.75;
  color: var(--SmartThemeBorderColor);
  font-size: 1.2em;
}

.swipe_right::before {
  content: "\f101";
}

.swipe_left::before {
  content: "\f100";
 }

/* by KAKAA */
.swipeRightBlock {
  flex-direction: row-reverse;
  bottom: calc(var(--swipeCounterHeight) + var(--swipeCounterMargin));
  margin-right: 15px;
}

.swipes-counter {
  transform: translate(25%, 20%);
}

/* ---名字区域 --- */
.mes .ch_name {
  order: 1;
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  margin-bottom: 2px;
  align-items: center;
}

/* 📌文字装饰(可自定义) */
.mes .ch_name::before {
  content: "× × 择 日 再 见 面 × ×";
  position: absolute;
  transform: translateX(-50%);
  left: 50%;
  font-size: calc(var(--mainFontSize) * 0.75);
}

.ch_name:has(.extraMesButtonsHint[style*="opacity: 0"])::before,
.ch_name:has(.mes_edit_buttons:not([style*="display: none"]))::before {
  display: none !important;
}

/* --- 📌名字(可自定义) --- */
.mes .name_text {
  position: absolute;
  top: 75px;
  left: 45px;
  writing-mode: vertical-rl;
  &::before {
    content: "文/";
  }
  &::after {
    content: "《仲夏夜之梦》";
    font-size: 1.3em;
    position: absolute;
    white-space: nowrap;
    top: -75px;
    right: 100%;
    margin-right: 5px;
  }
}
/* 手机端修改字体大小 */
@media (max-width: 768px) {
  .mes .name_text {
    font-size: 14px;
  }
}

/* --- 📌时间戳(位置调整) --- */
.mes .timestamp {
  position: absolute;
  top: calc(100% - 25px);
  left: 50%;
  transform: translateX(-50%);
  padding: 1px 5px;
  background: #fff;
  opacity: 1;
}

.last_mes[is_user="false"] .timestamp {
  top: calc(100% - 55px);
}

/* --- 📌头像区域(图床链接更换) --- */
.mesAvatarWrapper {
  display: flex;
  align-self: flex-start;
  align-items: flex-end;
  justify-content: flex-end;
  width: 100%;
  height: 170px; /* 整体高度调整① */
  flex: 0 0 auto;
  gap: 5px;
  margin-bottom: 2px;
  padding-bottom: 5px !important;
  border-bottom: 1.2px solid var(--SmartThemeBorderColor);
  &::before {
    content: "";
    position: absolute;
    top: 8px;
    right: 8px;
    width: 77%;
    height: 130px;/* 高度调整② */
    background: url("https://files.catbox.moe/ibvgek.jpg");*/ 
    background-repeat: no-repeat;
    background-size: 100% auto;
    background-position: 100% 70%; /* 图片上下显示位置(第二个百分比) */
    border-radius: 5px;
    opacity: 0.75; /*透明度*/
   /* filter: saturate(0.5);  饱和度 */
    box-shadow: -1px 2px 3px rgba(55, 55, 55, 0.25);
  }
}

/* 📌文案自定义 */
.mes .avatar {
  position: relative;
  bottom: -8px;
  &::after {
    content: "“是我引诱你吗？我曾经向你说过好话吗？我不是曾经明明白白地告诉过你，我不爱你，而且也不能爱你吗？”";/* user文案修改-手动换行使用\A换行符 */
    white-space: pre-wrap;
    font-size: 0.65em;/*字体大小*/
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    margin-left: -5px;
    color: var(--SmartThemeEmColor);
  }
}
/* char-文案修改 */
.mes[is_user="false"] .avatar {
  position: relative;
  &::after {
    content: "“我是你的一条狗，狄米特律斯；你越是打我，我越是讨好你。”";
  }
}

.mes .avatar img {
  bottom: 5px;
  transform: scale(0.55);
  outline: 1px solid var(--SmartThemeEmColor);
  outline-offset: 2px;
}

/* --- 楼层+计时器+tokens --- */
.mesIDDisplay:empty,
.mes_timer:empty,
.tokenCounterDisplay:empty {
  display: none !important;
}

.mes .mesIDDisplay,
.mes .mes_timer,
.mes .tokenCounterDisplay {
  opacity: 0.75;
  font-size: calc(var(--mainFontSize) * 0.75);
}

.mes .mes_timer,
.mes .tokenCounterDisplay {
  &::before {
    content: "/";
    margin-right: 5px;
    color: var(--SmartThemeEmColor);
  }
}

/* ===== 菜单抽屉 ===== */
#rm_button_characters,
#rm_button_panel_pin_div,
#lm_button_panel_pin_div,
#WI_button_panel_pin_div {
  font-size: calc(var(--mainFontSize) *1.2);
}

/* 反代警告 */
.reverse_proxy_warning {
    border-color: crimson !important;
    border-radius: 2px !important;
    background-color: transparent !important;
}

/* 可移动UI预设 */
#movingUIPresets{
  margin-top: 2px;
  margin-bottom: 0 !important;
}

/* --- 抽屉页背景 --- */
body .drawer-content {
  box-shadow: none;
  border-radius: 0 0 8px 8px;
  border-color: var(--SmartThemeBlurTintColor);
  border-bottom: 1px solid var(--SmartThemeBorderColor);
  background: url("https://files.catbox.moe/e5j6hn.jpg"),
    #fff;
  background-size: cover;
  background-repeat: no-repeat;
}

/* 预设页 & 角色管理页 */
@media (max-width: 600px) {
  #left-nav-panel,
  #right-nav-panel {
    max-height: calc(100dvh - var(--topBarBlockSize));
    border-radius: 0 0 8px 8px;
    border-color: var(--SmartThemeBlurTintColor);
    border-bottom: 1px solid var(--SmartThemeBorderColor);
    padding-right: 0;
  }
}

/* --- 标题栏 --- */
.standoutHeader,
.inline-drawer-header,
#theme-manager-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4:not(#theme-manager-header h4),
#top-settings-holder h4:not(#ai-config-button):not(#rightNavHolder):not(#theme-manager-header h4) {
  padding: 5px 8px;
  margin-bottom: 8px;
  border-radius: 5px;
  border: 0.5px solid var(--SmartThemeBorderColor);
  background:
    radial-gradient(55% 105% ellipse at left top, rgba(101, 101, 101, 0.45), transparent),
    radial-gradient(35% 60% ellipse at 65% 110%, rgba(255, 255, 255, 0.5), transparent),
    radial-gradient(120px circle at right center, rgba(170, 170, 170, 0.43), transparent),
    rgba(217, 217, 217, 1);
  box-shadow:
    0.5px 0.5px 0 0.7px rgba(154, 154, 154, 0.25),
    inset 0 0 12px rgba(255, 255, 255, 0.6),
    inset 0 0 4px rgba(255, 255, 255, 0.95);
  filter: 
    drop-shadow(1px 1px 1px rgba(136, 136, 136, 0.15))
    drop-shadow(0 0 1px rgba(179, 179, 179, 0.31))
    drop-shadow(0 0 2px rgba(153, 153, 153, 0.15)) !important;
}

/* 箭头 */
.inline-drawer-icon {
  color: var(--SmartThemeBorderColor);
  filter: drop-shadow(0 0 12px var(--SmartThemeBorderColor));
  opacity: 0.75;
  font-size: 1em;
}

.inline-drawer-icon::before {
  content: "\f56b" !important;
}

.inline-drawer-icon.up::before {
  content: "\f52d" !important;
}

/* --- 按钮 --- */
.menu_button:not(.mes_edit_buttons *) {
  box-shadow: 
    1px 1px 1px var(--混合),
    inset 0 0 15px var(--SmartThemeBlurTintColor);
